define(['jquery'], function($) {
    return {
        init: function(args) {
            var ajaxUrl = args.ajaxurl;
            var sesskey = args.sesskey;
            var isAdmin = args.isadmin;
            var currentUserId = args.userid;
            
            if (isAdmin) {
                // ==========================================
                // ADMIN LOGIC
                // ==========================================
                var courseSelect = $('#lc-admin-course-select');
                var adminResults = $('#lc-admin-results');
                var adminTbody = $('#lc-admin-tbody');

                // 1. Load all courses into dropdown on page load
                $.getJSON(ajaxUrl, { action: 'getallcourses', sesskey: sesskey })
                    .done(function(data) {
                        courseSelect.empty();
                        courseSelect.append(new Option('Select a course...', ''));
                        $.each(data, function(i, item) {
                            courseSelect.append(new Option(item.text, item.id));
                        });
                    });

                // 2. Listen for course selection
                courseSelect.on('change', function() {
                    var courseId = $(this).val();
                    if (!courseId) {
                        adminResults.hide();
                        return;
                    }

                    adminResults.show();
                    adminTbody.html('<tr><td colspan="2" class="text-center">Calculating times...</td></tr>');

                    // Fetch users and times for this course
                    $.getJSON(ajaxUrl, { action: 'getcoursereport', courseid: courseId, sesskey: sesskey })
                        .done(function(data) {
                            adminTbody.empty();
                            if (data.length === 0) {
                                adminTbody.html('<tr><td colspan="2" class="text-center">No students enrolled.</td></tr>');
                            } else {
                                $.each(data, function(i, row) {
                                    adminTbody.append('<tr><td>' + row.user + '</td><td>' + row.time + '</td></tr>');
                                });
                            }
                        });
                });

            } else {
                // ==========================================
                // USER LOGIC
                // ==========================================
                var userTable = $('#lc-user-table');
                var userTbody = $('#lc-user-tbody');
                var userLoading = $('#lc-user-loading');

                // Fetch user's enrolled courses and times immediately on page load
                $.getJSON(ajaxUrl, { action: 'getmyreport', userid: currentUserId, sesskey: sesskey })
                    .done(function(data) {
                        userLoading.hide();
                        userTable.show();
                        
                        if (data.length === 0) {
                            userTbody.html('<tr><td colspan="2" class="text-center">You are not enrolled in any courses.</td></tr>');
                        } else {
                            $.each(data, function(i, row) {
                                userTbody.append('<tr><td>' + row.course + '</td><td>' + row.time + '</td></tr>');
                            });
                        }
                    });
            }
        }
    };
});